SELECT DISTINCT STRFTIME('%Y', purchase_date) AS purchase_year
FROM customer_purchase_history
WHERE customer_id = 1;

SELECT customer_id
FROM customer_purchase_history
WHERE purchase_date = (SELECT MAX(purchase_date) FROM customer_purchase_history);

SELECT first_name, last_name
FROM customers
WHERE customer_id IN (SELECT customer_id FROM customer_purchase_history);

SELECT COUNT(DISTINCT customer_id)
FROM customer_interactions
WHERE interaction_type_id = 1;

SELECT customer_id, note_date, note_text
FROM customer_notes
WHERE note_text LIKE '%question%';
